var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐야. 신나게 놀 줄 알았더니 분위기가 썰렁하네.","JPN":"何なの。楽しく遊べると思って来たのに、この冷めた雰囲気は。","ENG":"What? I thought we'd be having a party. What a drag.","TWN":"怎麼回事？我還以為會玩得很開心，結果氣氛好冷喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"디스코볼도 없고, DJ를 부른 것도 아니고. 너무 얌전 떠는 거 아니야?","JPN":"ミラーボールもなければ、DJも呼んでない。ちょっと大人しすぎるんじゃない？","ENG":"No disco ball, and even no DJ? Don't you think it's a little too quiet?","TWN":"沒有迪斯可球，也沒有DJ炒熱氣氛，不覺得有點安靜嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"응? 계약?","JPN":"うん？　契約？","ENG":"Hmm? A contract?","TWN":"嗯？契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"의외로 섬세한 구석도 있었네. 그렇게 안 봤는데~","JPN":"意外と繊細なところもあったのね。そうは見えなかったけど～","ENG":"Didn't take you to be such a delicate soul.","TWN":"沒想到你也有細心的一面呢，看不出來喔～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"호흡이 안 맞는다고 생각했으면 이런 회사는 벌써 떠나 버렸을걸?","JPN":"息が合わないと思っていたら、こんな会社、とっくの昔にサヨナラしてたわ。","ENG":"If I thought we didn't make a great team, I would've left this company ages ago.","TWN":"要是我覺得跟你不合的話，早就離開這種公司啦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"나는 챔피언으로서, 내 수준에 걸맞은 스태프들이랑 일할 의무가 있으니까.","JPN":"私はチャンピオンとして、レベルの合うスタッフと仕事をする義務があるの。","ENG":"As champion, I have a duty to work with staff befitting my talents.","TWN":"畢竟我身為冠軍，有義務要和符合我水準的工作人員共事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그게 바로 내가 경기장에서 받는 기대에 해 줄 수 있는 최선의 보답이야.","JPN":"それが最高のお返しだもの。競技場で私にかけられた期待に応えるね。","ENG":"Because that's the best way I can repay the expectations I get from everyone in the stadium.","TWN":"這樣才對得起大家對於我在比賽中的期待。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어차피 경기 결과야 당연히 내가 이기는 걸로 정해졌단 말씀~","JPN":"どうせ試合結果なんて、私が勝つに決まっているし～","ENG":"And, well, we don't even need to talk about the results. I'm going to win!","TWN":"不過反正結果一定是我贏啦～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"괜히 왕의 이름을 내건 게 아니라고.","JPN":"伊達に王の名を付けてるわけじゃないってこと。","ENG":"I'm not named after the king for nothing, you know.","TWN":"畢竟我可不是浪得虛名的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후. 어때? 이제 이해됐어?","JPN":"ふふ。どう？　これでわかったかしら？","ENG":"Fu fuu. So? Do you get it now?","TWN":"呵呵，怎麼樣？這樣你懂嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내가 여기 왔다는 것만으로도 대답은 끝난 거야.","JPN":"私がここに来たというだけで、答えは決まったも同然。","ENG":"I've already given you my answer by just being here.","TWN":"出現在這裡就是我的回答。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그럼 도장 찍자마자 신나게 놀 준비를 해 두는 게 당연하잖아?","JPN":"ハンコを押すと同時に楽しく遊ぶ準備ができていて当たり前でしょう？","ENG":"Then, isn't it obvious that you should've come prepared to party as soon as I sign it?","TWN":"那蓋完章後，應該就可以準備開趴吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어쩔 수 없지. 마침 내 친구들이 오늘 호텔에서 밤새도록 논다고 하거든.","JPN":"仕方ないわね。ちょうど友達から今日ホテルで夜通し遊ぶって聞いているわ。","ENG":"Oh, well. My friends have already contacted me saying that they're going to party all night at a hotel tonight.","TWN":"有什麼辦法，我的朋友剛好約我今天要在飯店徹夜狂歡。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"별난 애들도 많겠지만 따분하진 않을 거야.","JPN":"変わった子も多いけど、退屈はしないはずよ。","ENG":"There might be a few weirdos, but at least it won't be boring.","TWN":"是有很多怪咖啦，但絕對不無聊喔。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"특별 게스트로 소개해 줄 테니까, 거기선 그렇게 뻣뻣하게 굴지 말라구? 코치.","JPN":"特別ゲストとして紹介してあげるから、そこでも今みたいにかしこまっていないでよ、コーチ？","ENG":"C'mon, Coach. Try to loosen up a bit. I'll even introduce you as the special guest, okay?","TWN":"我會介紹你是我的特別嘉賓，你到時候可別一臉尷尬的樣子喔，教練？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};